func sortMailboxes(mbs []models.Mailbox) []models.Mailbox {
	sorted := make([]models.Mailbox, len(mbs))
	copy(sorted, mbs)

	priority := map[string]int{
		"inbox": 1,
		"sent":  2,
		"trash": 3,
	}

	sort.Slice(sorted, func(i, j int) bool {
		nameI := strings.ToLower(sorted[i].Name)
		nameJ := strings.ToLower(sorted[j].Name)

		pI, okI := priority[nameI]
		pJ, okJ := priority[nameJ]

		if okI && okJ {
			return pI < pJ
		}
		if okI {
			return true
		}
		if okJ {
			return false
		}
		return nameI < nameJ
	})

	return sorted
}

func getInboxID(mbs []models.Mailbox) uuid.UUID {
	for _, mb := range mbs {
		if strings.ToLower(mb.Name) == "inbox" {
			return mb.ID
		}
	}
	if len(mbs) > 0 {
		return mbs[0].ID
	}
	return uuid.Nil
}

func getInitials(name string) string {
	if name == "" {
		return "?"
	}
	parts := strings.Fields(name)
	if len(parts) > 1 {
		return strings.ToUpper(parts[0][:1] + parts[1][:1])
	}
	if len(name) > 1 {
		return strings.ToUpper(name[:1])
	}
	return strings.ToUpper(name)
}

func getAvatarColor(name string) string {
	colors := []string{"bg-blue-100 text-blue-700", "bg-purple-100 text-purple-700", "bg-pink-100 text-pink-700", "bg-indigo-100 text-indigo-700", "bg-teal-100 text-teal-700", "bg-orange-100 text-orange-700"}
	sum := 0
	for _, r := range name {
		sum += int(r)
	}
	return colors[sum%len(colors)]
}

